package com.shecancode.order.model; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDateTime; @Entity @Table(name="customer_orders") public class CustomerOrder { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(unique=true) private String orderNumber; private Long userId; private BigDecimal totalAmount; private String status="PENDING"; private String deliveryAddress; private LocalDateTime createdAt=LocalDateTime.now(); public Long getId(){return id;} public String getOrderNumber(){return orderNumber;} public void setOrderNumber(String v){orderNumber=v;} public Long getUserId(){return userId;} public void setUserId(Long v){userId=v;} public BigDecimal getTotalAmount(){return totalAmount;} public void setTotalAmount(BigDecimal v){totalAmount=v;} public String getStatus(){return status;} public void setStatus(String v){status=v;} public String getDeliveryAddress(){return deliveryAddress;} public void setDeliveryAddress(String v){deliveryAddress=v;} public LocalDateTime getCreatedAt(){return createdAt;} }